bool characterAllowedInUsername(char testChar) {
    return (
        (testChar == '_') ||
        (testChar >= '0' && testChar <= '9') ||
        (testChar >= 'A' && testChar <= 'Z') ||
        (testChar >= 'a' && testChar <= 'z')
    );
    // We only allow Roman letters, numbers, and underscores.
}

